/// Main object exercising self-references, state, errors, and Arc semantics.
final class Coveralls {
  Coveralls._(this._ffi, this._handle) {
    _finalizer.attach(this, _CoverallsFinalizerToken(_ffi._coverallsFree, _handle), detach: this);
  }

  final CoverallDemoFfi _ffi;
  int _handle;
  bool _closed = false;

  static final Finalizer<_CoverallsFinalizerToken> _finalizer = Finalizer((token) {
    token.free(token.handle);
  });

  bool get isClosed => _closed;

  void close() {
    if (_closed) {
      return;
    }
    _closed = true;
    _finalizer.detach(this);
    _ffi._coverallsFree(_handle);
  }

  void _ensureOpen() {
    if (_closed) {
      throw StateError('Coveralls is closed');
    }
  }

  static Coveralls fallibleNew(String name, bool shouldFail) {
    return _bindings().coverallsCreateFallibleNew(name, shouldFail);
  }

  static Coveralls create(String name) {
    return _bindings().coverallsCreateNew(name);
  }

  /// Add a patch to this coveralls.
  void addPatch(Patch patch) {
    _ensureOpen();
    _ffi.coverallsInvokeAddPatch(_handle, patch);
  }

  /// Add a repair record.
  void addRepair(Repair repair) {
    _ensureOpen();
    _ffi.coverallsInvokeAddRepair(_handle, repair);
  }

  /// Clone into a new instance (tests object return from method).
  Coveralls cloneMe() {
    _ensureOpen();
    return _ffi.coverallsInvokeCloneMe(_handle);
  }

  /// Return a string-keyed map.
  Map<String, int> getDict2(String key, int value) {
    _ensureOpen();
    return _ffi.coverallsInvokeGetDict2(_handle, key, value);
  }

  /// Return a non-string-keyed map.
  Map<int, int> getDict3(int key, int value) {
    _ensureOpen();
    return _ffi.coverallsInvokeGetDict3(_handle, key, value);
  }

  /// Return a map with string keys and optional string values.
  Map<String, String?> getMetadata() {
    _ensureOpen();
    return _ffi.coverallsInvokeGetMetadata(_handle);
  }

  String getName() {
    _ensureOpen();
    return _ffi.coverallsInvokeGetName(_handle);
  }

  Coveralls? getOther() {
    _ensureOpen();
    return _ffi.coverallsInvokeGetOther(_handle);
  }

  /// Return all stored repairs.
  List<Repair> getRepairs() {
    _ensureOpen();
    return _ffi.coverallsInvokeGetRepairs(_handle);
  }

  /// Simple pass-through returning the status string.
  String getStatus(String status) {
    _ensureOpen();
    return _ffi.coverallsInvokeGetStatus(_handle, status);
  }

  /// Return a sequence of optional strings.
  List<String?> getTags() {
    _ensureOpen();
    return _ffi.coverallsInvokeGetTags(_handle);
  }

  /// Method that always throws a simple error.
  bool maybeThrow(bool shouldThrow) {
    _ensureOpen();
    return _ffi.coverallsInvokeMaybeThrow(_handle, shouldThrow);
  }

  /// Method that throws a complex (rich) error.
  bool maybeThrowComplex(int selector) {
    _ensureOpen();
    return _ffi.coverallsInvokeMaybeThrowComplex(_handle, selector);
  }

  /// Another throws variant — returns boolean.
  bool maybeThrowInto(bool shouldThrow) {
    _ensureOpen();
    return _ffi.coverallsInvokeMaybeThrowInto(_handle, shouldThrow);
  }

  /// Reverse some bytes via a method (tests binary on object).
  Uint8List reverseBytes(Uint8List input) {
    _ensureOpen();
    return _ffi.coverallsInvokeReverseBytes(_handle, input);
  }

  /// Empty record round-trip.
  EmptyStruct setAndGetEmptyStruct(EmptyStruct emptyStruct) {
    _ensureOpen();
    return _ffi.coverallsInvokeSetAndGetEmptyStruct(_handle, emptyStruct);
  }

  void setName(String name) {
    _ensureOpen();
    _ffi.coverallsInvokeSetName(_handle, name);
  }

  /// Strong reference count (tests Self=ByArc on the Rust side).
  int strongCount() {
    _ensureOpen();
    return _ffi.coverallsInvokeStrongCount(_handle);
  }

  /// Take another Coveralls, creating a reference chain.
  void takeOther(Coveralls? other) {
    _ensureOpen();
    _ffi.coverallsInvokeTakeOther(_handle, other);
  }

}

